import React, { useState } from 'react';
const SOCIALS = [
  { label: 'GitHub',   href: 'https://github.com',   icon: '⌥' },
  { label: 'LinkedIn', href: 'https://linkedin.com',  icon: 'in' },
  { label: 'Twitter',  href: 'https://twitter.com',   icon: '𝕏'  },
  { label: 'Email',    href: 'mailto:alex@example.com', icon: '✉' },
];

function Contact() {
  const [form,   setForm]   = useState({ name: '', email: '', message: '' });
  const [status, setStatus] = useState('idle'); /* idle | sending | sent | error */

  const handleChange = (e) => {
    setForm(prev => ({ ...prev, [e.target.name]: e.target.value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setStatus('sending');
    /* Simulate a network request — wire up your real endpoint here */
    await new Promise(r => setTimeout(r, 1200));
    setStatus('sent');
    setForm({ name: '', email: '', message: '' });
  };

  return (
    <section id="contact" className="contact">
      <div className="container contact__inner">
        {/* Left */}
        <div className="contact__left">
          <p className="section-tag">Contact</p>
          <h2 className="section-title">
            Let's build<br />
            something great
          </h2>
          <p className="contact__blurb">
            I'm always open to interesting projects, collaborations, or
            just a friendly chat about tech. Drop me a message and I'll
            get back to you within 24 hours.
          </p>

          <div className="contact__socials">
            {SOCIALS.map(s => (
              <a
                key={s.label}
                href={s.href}
                target="_blank"
                rel="noopener noreferrer"
                className="contact__social"
                aria-label={s.label}
              >
                <span className="contact__social-icon">{s.icon}</span>
                <span className="contact__social-label">{s.label}</span>
              </a>
            ))}
          </div>
        </div>

        {/* Right — form */}
        <div className="contact__right">
          {status === 'sent' ? (
            <div className="contact__success">
              <span className="contact__success-icon">✓</span>
              <h3>Message sent!</h3>
              <p>Thanks for reaching out. I'll reply within a day.</p>
              <button className="btn btn--ghost" onClick={() => setStatus('idle')}>
                Send another
              </button>
            </div>
          ) : (
            <form className="contact__form" onSubmit={handleSubmit} noValidate>
              <div className="contact__row">
                <div className="contact__field">
                  <label htmlFor="name" className="contact__label">Name</label>
                  <input
                    id="name" name="name" type="text"
                    className="contact__input"
                    placeholder="Jane Smith"
                    value={form.name}
                    onChange={handleChange}
                    required
                  />
                </div>
                <div className="contact__field">
                  <label htmlFor="email" className="contact__label">Email</label>
                  <input
                    id="email" name="email" type="email"
                    className="contact__input"
                    placeholder="jane@example.com"
                    value={form.email}
                    onChange={handleChange}
                    required
                  />
                </div>
              </div>
              <div className="contact__field">
                <label htmlFor="message" className="contact__label">Message</label>
                <textarea
                  id="message" name="message"
                  className="contact__input contact__textarea"
                  placeholder="Tell me about your project..."
                  rows={6}
                  value={form.message}
                  onChange={handleChange}
                  required
                />
              </div>
              <button
                type="submit"
                className="btn btn--primary contact__submit"
                disabled={status === 'sending'}
              >
                {status === 'sending' ? 'Sending…' : 'Send Message →'}
              </button>
            </form>
          )}
        </div>
      </div>
    </section>
  );
}

export default Contact;
